WHERE r.IS_PRIMARY = 1
  AND r.IS_DELETED = 0
  AND r.ALLOW_SCOUT = 1


  AND (
        LOWER(m.NAME) LIKE '%' || LOWER(#{keyword}) || '%'
     OR LOWER(r.TITLE) LIKE '%' || LOWER(#{keyword}) || '%'
     OR LOWER(jc.CATEGORY_NAME) LIKE '%' || LOWER(#{keyword}) || '%'
  )



  AND r.FK_CATEGORY_ID IN

    #{categoryId}




  AND r.FK_REGION_CODE = #{regionCode}



  AND r.DESIRED_SALARY >= #{salaryMin}



  AND r.DESIRED_SALARY <= #{salaryMax}



  AND EXISTS (
    SELECT 1
    FROM TBL_RESUME_TECHSTACK rt
    WHERE rt.FK_RESUME_ID = r.RESUME_ID
      AND rt.FK_SKILL_ID IN

        #{skillId}

  )



  AND (
    SELECT NVL(FLOOR(SUM(MONTHS_BETWEEN(NVL(c.LEAVEDATE, SYSDATE), c.JOINDATE)) / 12), 0)
    FROM TBL_RESUME_CAREER c
    WHERE c.FK_RESUME_ID = r.RESUME_ID
  ) >= #{careerMin}



  AND (
    SELECT NVL(FLOOR(SUM(MONTHS_BETWEEN(NVL(c.LEAVEDATE, SYSDATE), c.JOINDATE)) / 12), 0)
    FROM TBL_RESUME_CAREER c
    WHERE c.FK_RESUME_ID = r.RESUME_ID
  ) <= #{careerMax}



  AND EXISTS (
    SELECT 1
    FROM TBL_RESUME_EDUCATION e
    JOIN TBL_EDUCATION_LEVEL el
      ON e.FK_EDU_LEVEL_CODE = el.EDU_LEVEL_CODE
    WHERE e.FK_RESUME_ID = r.RESUME_ID
      AND el.EDU_LEVEL_NAME = #{educationLevel}
  )



  AND r.UPLOADED_AT >= SYSDATE - #{updatedWithin}



  AND EXISTS (
    SELECT 1
    FROM TBL_RESUME_PORTFOLIO p
    WHERE p.FK_RESUME_ID = r.RESUME_ID
  )
